import{_ as e,o as t,c as n,ae as s}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Pre-Install Analytics Overview","description":"","frontmatter":{"title":"Pre-Install Analytics Overview","slug":"pre-install-analytics"},"headers":[],"relativePath":"developer-hub/pre-install-analytics.md","filePath":"developer-hub/pre-install-analytics.md"}'),i={name:"developer-hub/pre-install-analytics.md"};function l(r,a,o,p,c,d){return t(),n("div",null,[...a[0]||(a[0]=[s(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Many mobile devices come with apps already installed, which is great for the user experience since users do not need to launch an app store to download and install these pre-loaded apps. But how do you attribute the pre-loaded app install when there is no ad click to use for attributing the install to the appropriate advertising partner?</p><p>Branch solves this problem by allowing you to set all of the relevant partner/publisher information in the app itself, which we then collect during the install request <strong>on Android only</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Specific Partner Guides</p><p>There are specific partner guides available for Pre-Install attribution. Visit them here:</p><ul><li><a href="./xiaomi-pre-install.html">Xiaomi</a></li><li><a href="./oppo-pre-install.html">Oppo</a></li><li><a href="./vivo-pre-install.html">Vivo</a></li></ul></div><h2 id="how-does-it-work" tabindex="-1">How Does It Work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How Does It Work?&quot;">​</a></h2><ol><li><p>You have agreed with a wireless carrier/OEM (ex. AT&amp;T) to pre-install your mobile app on their devices. In this case, the wireless carrier/OEM is the advertising partner.</p></li><li><p>The ad partner&#39;s information is supplied to the app via the Branch Android SDK.</p></li><li><p>On the app&#39;s first open, the Branch Android SDK collects the advertiser&#39;s information and uses it to attribute the app install and downstream app events (<code>COMPLETE_REGISTRATION</code> for example) to the partner.</p><ul><li>Events occurring in the first launch of the app will be attributed back to the partner (even if a Branch Link was clicked before the app was first opened). If there is then a later click, that will become the new most recent last touch, and future events will be attributed to that link click.</li></ul></li></ol><div class="info custom-block"><p class="custom-block-title">Attribution Priority</p><p>All Preload Attribution Methods take priority over other attribution sources such as clicks and impressions. Preload Attribution Windows adhere to those set within the Branch Dashboard.</p></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>To enable, you first need to:</p><ol><li>Create a Branch Dashboard.</li><li>Integrate the <a href="./android-basic-integration.html">Branch Android SDK</a> v4.0.0+ into your mobile app.</li></ol><h2 id="default-pre-install-analytics" tabindex="-1">Default Pre-Install Analytics <a class="header-anchor" href="#default-pre-install-analytics" aria-label="Permalink to &quot;Default Pre-Install Analytics&quot;">​</a></h2><p>By default, the Android SDK will utilize the <a href="./branch-methodology-overview.html#install-referrers">Google Play Store Install Referrer API</a> to evaluate specific indicators that would require Branch-related handling.</p><p>In terms of preload attribution, Branch specifically looks for the value <code>play-auto-install</code> - this value indicates that the app was pre-installed on the device at the carrier/OEM level and that even with a hard reset of the device, the app will still be present.</p><p>This <code>play-auto-install</code> value comes in the following format from the referrer API:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>utm_source=play-auto-installs&amp;utm_medium=preload&amp;utm_campaign={Campaign set by advertiser}</span></span></code></pre></div><p>Branch then maps the <code>utm_medium</code> and <code>utm_campaign</code> to <code>~channel</code> and <code>~campaign</code> respectively.</p><h2 id="enable-advanced-pre-install-analytics" tabindex="-1">Enable Advanced Pre-Install Analytics <a class="header-anchor" href="#enable-advanced-pre-install-analytics" aria-label="Permalink to &quot;Enable Advanced Pre-Install Analytics&quot;">​</a></h2><p>There are two options for enabling advanced pre-install analytics with Branch.</p><div class="info custom-block"><p class="custom-block-title">Preload Partner Values</p><p>When setting pre-loaded partner data, you must use Branch&#39;s <code>$3p</code> value for the partner&#39;s name, which will override the system props data. Follow our <a href="./testing-universal-ads-campaign-setup.html#section-how-to-find-a-partners-webhook-key">guide</a> on how to find a partner&#39;s <code>$3p</code> value.</p></div><h3 id="option-1-pre-loaded-apk" tabindex="-1">Option 1: Pre-loaded APK <a class="header-anchor" href="#option-1-pre-loaded-apk" aria-label="Permalink to &quot;Option 1: Pre-loaded APK&quot;">​</a></h3><p>After loading the Branch Android SDK in the <code>Application</code> class (see <a href="./android-basic-integration.html#section-load-branch">docs</a>), call the setters to set the data in the APK:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Branch object initialization</span></span>
<span class="line"><span>Branch.getAutoInstance(this);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Set campaign</span></span>
<span class="line"><span>Branch.getInstance().setPreinstallCampaign(&quot;My Campaign Name&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Set partner $3p value</span></span>
<span class="line"><span>Branch.getInstance().setPreinstallPartner(&quot;Branch $3p Parameter Value&quot;);</span></span></code></pre></div><p>Measuring the logs, the request should look like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  …</span></span>
<span class="line"><span>  preinstall_campaign: “My Campaign Name”</span></span>
<span class="line"><span>  preinstall_partner: “Branch $3p Parameter Value”</span></span>
<span class="line"><span>  …</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Multiple Partners Pre-Installing Your App</p><p>If multiple partners are pre-installing your mobile app, then you can create a partner-specific build of your app for distribution to each publishing partner (where each build includes different partner settings, respective to the particular partner). The partner-specific build is what the partner pre-installs onto the desired devices.</p></div><h3 id="option-2-pre-loaded-device-data" tabindex="-1">Option 2: Pre-loaded Device Data <a class="header-anchor" href="#option-2-pre-loaded-device-data" aria-label="Permalink to &quot;Option 2: Pre-loaded Device Data&quot;">​</a></h3><p>Once the data is set, you need to read the pre-loaded data from the Android System Properties.</p><ol><li>Create a JSON file <code>pre_install_apps.branch</code> as follows:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>    &quot;apps&quot;: {</span></span>
<span class="line"><span>        &quot;application.package.name&quot;: {</span></span>
<span class="line"><span>            &quot;preinstall_partner&quot;: &quot;Branch $3p Parameter Value&quot;,</span></span>
<span class="line"><span>            &quot;preinstall_campaign&quot;: &quot;campaign_to_attribute&quot;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><ol start="2"><li>Ask the device manufacturer to add the file in the OS level file system.</li><li>Set the file path in the build.props as below:<br><code>io.branch.preinstall.apps.path=/pre_install_apps.branch</code></li><li>The SDK checks if the APK has the pre-install data.</li></ol><h2 id="enable-referring-url-attribution" tabindex="-1">Enable Referring URL Attribution <a class="header-anchor" href="#enable-referring-url-attribution" aria-label="Permalink to &quot;Enable Referring URL Attribution&quot;">​</a></h2><p>By default, Branch prioritizes pre-install attribution on pre-installed apps. However, it is also possible to prioritize the referring link over pre-install attribution.</p><p>To do so, use the <code>setReferringLinkAttributionForPreinstalledAppsEnabled()</code> method, which enables referring URL attribution for pre-installed apps.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Enable referring URL attribution prior to initialization</span></span>
<span class="line"><span>Branch.getInstance().setReferringLinkAttributionForPreinstalledAppsEnabled();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Branch object initialization</span></span>
<span class="line"><span>Branch.getAutoInstance(this);</span></span></code></pre></div><h2 id="view-pre-install-data-in-branch" tabindex="-1">View Pre-Install Data in Branch <a class="header-anchor" href="#view-pre-install-data-in-branch" aria-label="Permalink to &quot;View Pre-Install Data in Branch&quot;">​</a></h2><p>Regardless of your Pre-Install Analytics Method, Branch will hard-code <code>channel</code> to <code>preinstall</code>.</p><p>While in the <strong>Ads Analytics</strong> section of the Branch Dashboard, filter first for <code>channel=preinstall</code> and continue to segment your data further by adding additional parameters in the <strong>Compare by</strong> row.</p>`,37)])])}const b=e(i,[["render",l]]);export{u as __pageData,b as default};
